124→    async fn start_account(
125→        &mut self,
126→        account_id: &str,
127→        config: serde_json::Value,
128→    ) -> ChannelResult<()> {
129→        let cfg: SlackAccountConfig = serde_json::from_value(config)?;
130→        if cfg.bot_token.expose_secret().is_empty() {
131→            return Err(ChannelError::invalid_input("Slack bot_token is required"));
132→        }
133→
134→        match cfg.connection_mode {
135→            crate::config::ConnectionMode::SocketMode => {
136→                if cfg.app_token.expose_secret().is_empty() {
137→                    return Err(ChannelError::invalid_input(
138→                        "Slack app_token is required for Socket Mode",
139→                    ));
140→                }
141→                info!(account_id, "starting slack account (socket mode)");
142→                crate::socket::start_socket_mode(
143→                    account_id,
144→                    cfg,
145→                    Arc::clone(&self.accounts),
146→                    self.message_log.clone(),
147→                    self.event_sink.clone(),
148→                )
149→                .await
150→            },
151→            crate::config::ConnectionMode::EventsApi => {
152→                if cfg
153→                    .signing_secret
154→                    .as_ref()
155→                    .is_none_or(|s| s.expose_secret().is_empty())
156→                {
157→                    return Err(ChannelError::invalid_input(
158→                        "Slack signing_secret is required for Events API mode",
159→                    ));
160→                }
161→                info!(account_id, "starting slack account (events api)");
162→                crate::webhook::register_events_api_account(
163→                    account_id,
164→                    cfg,
165→                    Arc::clone(&self.accounts),
166→                    self.message_log.clone(),
167→                    self.event_sink.clone(),
168→                )
169→                .await
170→            },
171→        }
172→    }
173→
174→    async fn stop_account(&mut self, account_id: &str) -> ChannelResult<()> {
175→        let cancel = {
176→            let mut accounts = self.accounts.write().unwrap_or_else(|e| e.into_inner());
177→            accounts.remove(account_id).map(|s| s.cancel)
178→        };
179→        if let Some(cancel) = cancel {
180→            cancel.cancel();
181→            info!(account_id, "stopped slack account");
182→        } else {
183→            warn!(account_id, "slack account not found");
184→        }
185→        Ok(())
186→    }
