220→    fn update_account_config(
221→        &self,
222→        account_id: &str,
223→        config: serde_json::Value,
224→    ) -> ChannelResult<()> {
225→        let parsed: SlackAccountConfig = serde_json::from_value(config)?;
226→        let mut accounts = self.accounts.write().unwrap_or_else(|e| e.into_inner());
227→        if let Some(state) = accounts.get_mut(account_id) {
228→            state.config = parsed;
229→            Ok(())
