253→        account_id: &str,
254→    ) -> Option<Box<dyn moltis_channels::channel_webhook_middleware::ChannelWebhookVerifier>> {
255→        let accounts = self.accounts.read().unwrap_or_else(|e| e.into_inner());
256→        let state = accounts.get(account_id)?;
257→        let secret = state.config.signing_secret.as_ref()?;
