265→impl ChannelStatus for SlackPlugin {
266→    async fn probe(&self, account_id: &str) -> ChannelResult<ChannelHealthSnapshot> {
267→        let accounts = self.accounts.read().unwrap_or_else(|e| e.into_inner());
268→        if let Some(state) = accounts.get(account_id) {
269→            let connected = state.bot_user_id.is_some();
270→            let details = if connected {
271→                "socket mode connected".to_string()
272→            } else {
273→                "connecting to Slack...".to_string()
274→            };
275→            Ok(ChannelHealthSnapshot {
276→                connected,
277→                account_id: state.account_id.clone(),
278→                details: Some(details),
279→                extra: None,
280→            })
281→        } else {
282→            Ok(ChannelHealthSnapshot {
283→                connected: false,
284→                account_id: account_id.to_string(),
285→                details: Some("account not started".into()),
286→                extra: None,
287→            })
288→        }
289→    }
290→}
