  1→//! Slack webhook verifier implementing [`ChannelWebhookVerifier`].
  2→//!
  3→//! Uses HMAC-SHA256 with the app's signing secret, following the
  4→//! [Slack verification protocol](https://api.slack.com/authentication/verifying-requests-from-slack).
  5→
  6→use {
  7→    bytes::Bytes,
  8→    http::HeaderMap,
  9→    moltis_channels::{
 10→        channel_webhook_middleware::{
 11→            ChannelWebhookRejection, ChannelWebhookVerifier, VerifiedChannelWebhook,
 12→        },
 13→        plugin::ChannelType,
 14→    },
 15→    secrecy::{ExposeSecret, Secret},
 16→};
 17→
 18→use crate::webhook::verify_signature;
 19→
 20→/// Slack Events API / Interactions webhook verifier.
 21→///
 22→/// Wraps the existing HMAC-SHA256 [`verify_signature`] function behind the
 23→/// shared [`ChannelWebhookVerifier`] trait.
 24→pub struct SlackChannelWebhookVerifier {
 25→    signing_secret: Secret<String>,
 26→}
 27→
 28→impl SlackChannelWebhookVerifier {
 29→    pub fn new(signing_secret: Secret<String>) -> Self {
 30→        Self { signing_secret }
 31→    }
 32→}
 33→
 34→impl ChannelWebhookVerifier for SlackChannelWebhookVerifier {
 35→    fn verify(
 36→        &self,
 37→        headers: &HeaderMap,
 38→        body: &[u8],
 39→    ) -> Result<VerifiedChannelWebhook, ChannelWebhookRejection> {
 40→        let timestamp = headers
 41→            .get("x-slack-request-timestamp")
 42→            .and_then(|v| v.to_str().ok())
 43→            .ok_or_else(|| {
 44→                ChannelWebhookRejection::MissingHeaders("x-slack-request-timestamp".into())
 45→            })?;
 46→
 47→        let signature = headers
 48→            .get("x-slack-signature")
 49→            .and_then(|v| v.to_str().ok())
 50→            .ok_or_else(|| ChannelWebhookRejection::MissingHeaders("x-slack-signature".into()))?;
 51→
 52→        if !verify_signature(
 53→            self.signing_secret.expose_secret(),
 54→            timestamp,
 55→            body,
 56→            signature,
 57→        ) {
 58→            return Err(ChannelWebhookRejection::BadSignature(
 59→                "invalid Slack webhook signature".into(),
 60→            ));
 61→        }
 62→
 63→        // Extract idempotency key from JSON `event_id` field (Events API).
 64→        let idempotency_key = serde_json::from_slice::<serde_json::Value>(body)
 65→            .ok()
 66→            .and_then(|v| v.get("event_id").and_then(|e| e.as_str()).map(String::from));
 67→
 68→        let timestamp_epoch = timestamp.parse::<i64>().ok();
 69→
 70→        Ok(VerifiedChannelWebhook {
 71→            idempotency_key,
 72→            body: Bytes::copy_from_slice(body),
 73→            timestamp_epoch,
 74→        })
 75→    }
 76→
 77→    fn rate_policy(&self) -> moltis_channels::ChannelWebhookRatePolicy {
 78→        moltis_channels::ChannelWebhookRatePolicy {
 79→            max_requests_per_minute: 30,
 80→            burst: 10,
 81→        }
 82→    }
 83→
 84→    fn channel_type(&self) -> ChannelType {
 85→        ChannelType::Slack
 86→    }
 87→}
