101→    /// Build valid Slack signature headers for a given body and timestamp.
102→    fn make_signed_headers(secret: &str, timestamp: &str, body: &[u8]) -> HeaderMap {
103→        let mut mac = Hmac::<Sha256>::new_from_slice(secret.as_bytes()).expect("valid HMAC key");
104→        mac.update(b"v0:");
105→        mac.update(timestamp.as_bytes());
106→        mac.update(b":");
107→        mac.update(body);
108→        let sig = mac.finalize().into_bytes();
109→        let hex = sig.iter().map(|b| format!("{b:02x}")).collect::<String>();
110→
111→        let mut headers = HeaderMap::new();
112→        headers.insert("x-slack-request-timestamp", timestamp.parse().unwrap());
113→        headers.insert("x-slack-signature", format!("v0={hex}").parse().unwrap());
114→        headers
115→    }
